import { Suspense } from 'react';
import Link from 'next/link';
import { sanityFetch } from "@/sanity/lib/live";
import { POST_QUERY } from "@/sanity/lib/queries";
import { PortableText } from '@portabletext/react';
import Image from 'next/image';
import { urlFor } from '@/sanity/lib/image';
import { client } from '@/sanity/lib/client';

export const unstable_instant = false;

// Generate static params for faster loads
export async function generateStaticParams() {
  const posts = await client.fetch(
    `*[_type == "post" && defined(slug.current)] { "slug": slug.current }`
  );
  
  return posts.map((p: any) => ({
    slug: p.slug,
  }));
}

export default async function PostPage(props: { params: Promise<{ slug: string }> }) {
  return (
    <Suspense fallback={<div className="p-10 font-sans tracking-widest text-[#a27725] bg-[#f6f3ee] min-h-screen flex items-center justify-center uppercase text-sm">Loading Post...</div>}>
      <PostContent params={props.params} />
    </Suspense>
  );
}

async function PostContent({ params }: { params: Promise<{ slug: string }> }) {
  const p = await params;
  const slug = p?.slug;

  if (!slug) {
    return <p className="p-10 bg-[#f6f3ee] text-[#1a1a1a]">Slug missing</p>;
  }

  const { data: post } = await sanityFetch({ 
    query: POST_QUERY,
    params: { slug }
  });

  if (!post) {
    return (
      <main className="bg-[#f6f3ee] text-[#1a1a1a] min-h-screen flex items-center justify-center">
        <div className="text-center">
          <h1 className="text-4xl font-serif mb-4">Post not found</h1>
          <Link href="/insights" className="text-[#a27725] underline">← Back to Insights</Link>
        </div>
      </main>
    );
  }

  return (
    <main className="bg-[#f6f3ee] text-[#1a1a1a] min-h-screen">

      <article className="pt-32 pb-32">
        {/* HEADER */}
        <header className="px-6 md:px-10 max-w-3xl mx-auto mb-16 pt-12">
          <p className="text-xs tracking-[0.3em] uppercase text-[#a27725] mb-8">Design Insight</p>
          <h1 className="text-4xl md:text-6xl font-light tracking-tight leading-[1.1] mb-8 font-serif text-[#1a1a1a]">
            {post.title}
          </h1>
          <div className="flex items-center gap-6 text-sm text-neutral-400 font-light border-b border-black/10 pb-8">
            <span>{post.author?.name || 'Laminate Gallery'}</span>
            <span>•</span>
            <span>{post.publishedAt ? new Date(post.publishedAt).toLocaleDateString('en-US', { month: 'long', year: 'numeric' }) : 'Recently'}</span>
            {post.readTime && (
              <>
                <span>•</span>
                <span>{post.readTime}</span>
              </>
            )}
          </div>
        </header>

        {/* CONTENT */}
        <section className="px-6 md:px-10 max-w-3xl mx-auto">
          <div className="
              prose-lg
              font-light leading-relaxed text-[#1a1a1a]/80

              [&>p]:mb-6 [&>p]:text-lg [&>p]:leading-relaxed

              [&>h2]:text-3xl [&>h2]:text-[#1a1a1a] [&>h2]:mt-16 [&>h2]:mb-6 [&>h2]:font-light [&>h2]:font-serif

              [&>img]:w-full [&>img]:rounded-2xl [&>img]:my-12 [&>img]:shadow-sm

              [&>blockquote]:border-l-2 [&>blockquote]:border-[#a27725] [&>blockquote]:pl-8 [&>blockquote]:my-12 [&>blockquote]:text-2xl [&>blockquote]:italic [&>blockquote]:text-[#1a1a1a]/70 [&>blockquote]:font-serif [&>blockquote]:leading-relaxed
            ">
            <PortableText 
              value={post.body} 
              components={{
                types: {
                  image: ({ value }) => (
                    <div className="my-12">
                      <Image
                        src={urlFor(value).width(1200).url()}
                        alt={value.alt || 'Content image'}
                        width={1200}
                        height={800}
                        className="w-full rounded-2xl shadow-sm"
                      />
                      {value.caption && <p className="text-center text-sm text-neutral-400 mt-4">{value.caption}</p>}
                    </div>
                  )
                }
              }}
            />
          </div>
        </section>

        {/* AUTHOR */}
        <section className="px-6 md:px-10 max-w-3xl mx-auto mt-20 pt-12 border-t border-black/10">
          <div className="flex items-center gap-5">
            {post.author?.image ? (
               <Image
                src={urlFor(post.author.image).width(100).height(100).url()}
                alt={post.author.name}
                width={56}
                height={56}
                className="rounded-full object-cover"
              />
            ) : (
              <div className="w-14 h-14 bg-[#1a1a1a] rounded-full flex items-center justify-center text-white font-serif italic text-xl shrink-0">L</div>
            )}
            <div>
              <p className="text-sm uppercase tracking-widest text-black font-medium">{post.author?.name || 'Laminate Gallery'}</p>
              <p className="text-sm text-neutral-500 font-light mt-1">
                {post.author?.bio ? <PortableText value={post.author.bio} /> : 'Luxury Interiors & Furniture Studio — Pune, India'}
              </p>
            </div>
          </div>
        </section>

        {/* MORE INSIGHTS CTA */}
        <section className="px-6 md:px-10 max-w-3xl mx-auto mt-16 pt-12 border-t border-black/10 text-center">
          <p className="text-sm tracking-widest uppercase text-neutral-400 mb-4">Continue exploring</p>
          <Link href="/insights" className="inline-block px-10 py-4 border border-black/20 rounded-full text-sm tracking-widest uppercase hover:bg-black hover:text-white transition-colors duration-500">
            All Insights
          </Link>
        </section>
      </article>
    </main>
  );
}

import { notFound } from "next/navigation";
import Image from "next/image";
import { client } from "@/sanity/lib/client";
import { sanityFetch } from "@/sanity/lib/live";
import { PROJECT_QUERY } from "@/sanity/lib/queries";
import { urlFor } from "@/sanity/lib/image";
import Link from 'next/link';

type Props = {
  params: Promise<{ slug: string }>;
};

export default async function CaseStudyPage({ params }: Props) {
  const { slug } = await params;

  if (!slug) return notFound();

  const { data: project } = await sanityFetch({
    query: PROJECT_QUERY,
    params: { slug }
  });

  if (!project) return notFound();

  return (
    <main className="bg-[#f5f3ef] text-[#1a1a1a]">

      {/* ================= HERO ================= */}
      <section className="relative h-[90vh] w-full overflow-hidden">
        {project.hero && (
           <Image
            src={urlFor(project.hero).width(1920).url()}
            className="absolute inset-0 object-cover"
            alt={project.title}
            fill
            priority
          />
        )}

        <div className="absolute inset-0 bg-black/30" />

        <div className="relative z-10 h-full flex items-end px-6 md:px-20 pb-16 text-white">
          <div className="max-w-2xl">
            <p className="text-xs tracking-[0.25em] opacity-70 mb-4 uppercase">
              FEATURED PROJECT
            </p>

            <h1 className="text-4xl md:text-6xl font-serif leading-tight font-light">
              {project.title.split(" ")[0]}{" "}
              <span className="italic">
                {project.title.split(" ").slice(1).join(" ")}
              </span>
            </h1>

            <p className="mt-6 text-white/80 max-w-md font-light leading-relaxed">
              {project.description}
            </p>
          </div>
        </div>
      </section>

      {/* ================= OVERVIEW ================= */}
      <section className="px-6 md:px-20 py-24 border-t border-[#e5e2dc]">
        <div className="grid md:grid-cols-4 gap-10 text-sm tracking-wide">
          <div>
            <p className="text-gray-400 mb-1 uppercase text-[10px] tracking-widest font-semibold">Location</p>
            <p className="font-light">{project.location}</p>
          </div>

          <div>
            <p className="text-gray-400 mb-1 uppercase text-[10px] tracking-widest font-semibold">Scope</p>
            <p className="font-light">{project.scope}</p>
          </div>

          <div>
            <p className="text-gray-400 mb-1 uppercase text-[10px] tracking-widest font-semibold">Area</p>
            <p className="font-light">{project.area}</p>
          </div>

          <div>
            <p className="text-gray-400 mb-1 uppercase text-[10px] tracking-widest font-semibold">Timeline</p>
            <p className="font-light">{project.timeline}</p>
          </div>
        </div>
      </section>

      {/* ================= CHALLENGE ================= */}
      <section className="px-6 md:px-20 py-24 max-w-3xl">
        <h2 className="text-3xl font-serif font-light mb-8">The Challenge</h2>
        <p className="text-gray-600 leading-relaxed font-light text-lg">
          {project.challenge}
        </p>
      </section>

      {/* ================= APPROACH ================= */}
      <section className="px-6 md:px-20 py-24 max-w-3xl border-t border-black/5">
        <h2 className="text-3xl font-serif font-light mb-8">The Approach</h2>
        <p className="text-gray-600 leading-relaxed font-light text-lg">
          {project.solution}
        </p>
      </section>

      {/* ================= GALLERY ================= */}
      <section className="px-6 md:px-20 py-28 bg-white/30">
        <div className="grid md:grid-cols-2 gap-8">
          {project.gallery?.map((img: { asset: { _ref: string } } | string, i: number) => (
            <div key={i} className="relative h-[500px] w-full rounded-2xl overflow-hidden shadow-sm">
              <Image
                src={urlFor(img).width(1200).url()}
                className="object-cover transition-transform duration-700 hover:scale-105"
                alt={`${project.title} Gallery ${i + 1}`}
                fill
              />
            </div>
          ))}
        </div>
      </section>

      {/* ================= HIGHLIGHTS ================= */}
      <section className="px-6 md:px-20 py-28 bg-[#ece9e4]">
        <h2 className="text-3xl font-serif font-light mb-20 text-center">
          Key Highlights
        </h2>

        <div className="grid md:grid-cols-3 gap-16 text-center">
          {project.highlights?.map((item: { title: string; text: string }, i: number) => (
            <div key={i} className="space-y-4">
              <p className="text-xs uppercase tracking-[0.2em] text-[#a27725] font-semibold">{item.title}</p>
              <p className="text-gray-600 font-light leading-relaxed">{item.text}</p>
            </div>
          ))}
        </div>
      </section>

      {/* ================= CTA ================= */}
      <section className="py-40 text-center bg-[#1a1a1a] text-white">
        <h2 className="text-5xl font-serif font-light mb-10">
          Start your <span className="italic">project</span> with us
        </h2>

        <Link href="/contact" className="px-10 py-4 border border-white rounded-full text-xs tracking-widest uppercase hover:bg-white hover:text-black transition duration-500 font-semibold">
          Contact Us
        </Link>
      </section>

    </main>
  );
}

// Generate static params for faster loads
export async function generateStaticParams() {
  const projects = await client.fetch(
    `*[_type == "project" && defined(slug.current)] { "slug": slug.current }`
  );
  
  return projects.map((p: any) => ({
    slug: p.slug,
  }));
}

"use client";

import { useState, useEffect, useRef } from "react";
import FadeUp from "../components/FadeUp";

export default function PropertyPage() {
  const [color, setColor] = useState<"red" | "green" | "blue" | "white" | "cream">("red");
  const [activeColor, setActiveColor] = useState<typeof color>("red");
  const [nextColor, setNextColor] = useState<typeof color | null>(null);
  const [isAnimating, setIsAnimating] = useState(false);

  const images = {
    red: "/images/living-red.jpg",
    green: "/images/living-green.jpg",
    blue: "/images/living-blue.jpg",
    white: "/images/living-white.jpg",
    cream: "/images/living-cream.jpg",
  };

  const handleColorChange = (newColor: typeof color) => {
    if (newColor === color) return;

    setActiveColor(newColor); // 🔥 instant UI feedback

    if (isAnimating) return;

    setNextColor(newColor);
    setIsAnimating(true);

    setTimeout(() => {
      setColor(newColor);
      setNextColor(null);
      setIsAnimating(false);
    }, 700);
  };
  const imageCache = useRef<Record<string, HTMLImageElement>>({});

  useEffect(() => {
    Object.entries(images).forEach(([key, src]) => {
      if (!imageCache.current[key]) {
        const img = new Image();
        img.src = src;
        imageCache.current[key] = img;
      }
    });
  }, []);
  return (
    <main className="min-h-screen bg-[#f8f8f8] text-black">
      {/* HERO */}
      <section className="pt-36 pb-24 px-6 md:px-12 max-w-[1400px] mx-auto border-b border-black/5">
        <div className="max-w-2xl">
          <FadeUp>
            <h1 className="text-4xl md:text-6xl font-light tracking-tight leading-tight">
              Explore{" "}
              <span className="serif italic">
                Living Spaces
              </span>
            </h1>
          </FadeUp>

          <FadeUp delay={0.2}>
            <p className="mt-6 text-neutral-500 text-lg">
              Discover premium interiors and visualize your ideal space with our interactive configurator.
            </p>
          </FadeUp>
        </div>
      </section>

      {/* CONFIGURATOR */}
      <section className="px-6 md:px-12 max-w-[1400px] mx-auto py-32">
        <div className="flex flex-col md:grid md:grid-cols-[1fr_1.4fr] gap-10 md:gap-16 items-start">

          {/* HEADINGS - order 1 on mobile */}
          <div className="order-1 md:col-start-1 md:row-start-1 w-full pt-4">
            <FadeUp>
              <h2 className="text-3xl md:text-5xl font-light tracking-tight">
                Living Room Configurator
              </h2>
            </FadeUp>
            <FadeUp delay={0.2}>
              <p className="text-neutral-500 mt-3 md:hidden">
                Change the palette and experience the transformation in real time.
              </p>
            </FadeUp>
          </div>

          {/* RIGHT IMAGE - order 2 on mobile */}
          <div className="order-2 w-full md:col-start-2 md:row-start-1 md:row-span-3">
            <FadeUp delay={0.3}>
              <div className="relative h-[340px] md:h-[640px] rounded-3xl overflow-hidden shadow-[0_20px_60px_rgba(0,0,0,0.15)]">
                <img
                  src={images[color]}
                  className="absolute inset-0 w-full h-full object-cover"
                  alt="Room visualization"
                />
                {nextColor && (
                  <img
                    src={images[nextColor]}
                    className="absolute inset-0 w-full h-full object-cover animate-reveal"
                    alt="Room transition"
                  />
                )}
              </div>
            </FadeUp>
          </div>

          {/* COLORS - order 3 on mobile */}
          <div className="order-3 w-full self-start md:col-start-1 md:row-start-2 mt-4">
            <FadeUp delay={0.3}>
              <p className="text-xs tracking-[0.2em] mb-8 text-neutral-400">
                COLOR PALETTE
              </p>
              <div className="flex gap-3 flex-wrap">
                {Object.keys(images).map((c) => (
                  <button
                    key={c}
                    aria-label={`Select ${c} color palette`}
                    className="relative flex flex-col items-center transition-all duration-300 hover:scale-105"
                    onClick={() => handleColorChange(c as typeof color)}
                  >
                    {activeColor === c && (
                      <span className="absolute -top-5 text-[9px] tracking-[0.15em] font-semibold text-neutral-700 uppercase whitespace-nowrap">
                        Selected
                      </span>
                    )}
                    <div
                      className={`w-11 h-11 rounded-lg overflow-hidden transition-all duration-300 ${
                        activeColor === c
                          ? "ring-[1.5px] ring-blue-600 ring-offset-[3px] ring-offset-[#f8f8f8]"
                          : "border border-black/10"
                      }`}
                    >
                      <img
                        src={`/images/picker-${c}.png`}
                        alt={`${c} swatch`}
                        className="w-full h-full object-cover"
                      />
                    </div>
                  </button>
                ))}
              </div>
            </FadeUp>
          </div>

          {/* TEXT - order 4 on mobile */}
          <div className="order-4 w-full self-end md:col-start-1 md:row-start-3 hidden md:block">
            <FadeUp delay={0.4}>
              <p className="max-w-md text-neutral-500 leading-relaxed text-lg">
                Each palette reshapes the mood of your living space.
                From bold statements to subtle elegance, explore possibilities effortlessly.
              </p>
            </FadeUp>
          </div>

          <div className="order-5 w-full md:hidden mt-2">
            <FadeUp delay={0.4}>
              <p className="text-neutral-500 leading-relaxed">
                Each palette reshapes the mood of your living space. Explore possibilities effortlessly.
              </p>
            </FadeUp>
          </div>

        </div>
      </section>

      {/* PROPERTIES */}
      <section className="px-6 md:px-12 max-w-[1400px] mx-auto pb-40">
        <FadeUp>
          <div className="mb-14">
            <h2 className="text-3xl md:text-4xl font-light tracking-tight">
              Featured Properties
            </h2>
          </div>
        </FadeUp>

        <div className="grid md:grid-cols-3 gap-10">
          {[
            { img: "/images/property-1.jpg", title: "Modern Apartment", location: "Mumbai", slug: "modern-apartment" },
            { img: "/images/property-2.jpg", title: "Luxury Villa", location: "Goa", slug: "luxury-villa" },
            { img: "/images/property-3.jpg", title: "Minimal Studio", location: "Bangalore", slug: "minimal-studio" },
          ].map((p, i) => (
            <FadeUp key={i} delay={i * 0.15}>
              <a href={`/projects/${p.slug}`} className="group cursor-pointer block">
                <div className="relative overflow-hidden rounded-xl">
                  <img
                    src={p.img}
                    className="w-full h-[280px] object-cover transition-transform duration-700 group-hover:scale-105"
                  />
                  <div className="absolute inset-0 bg-black/0 group-hover:bg-black/30 transition duration-500" />
                  <div className="absolute bottom-4 left-4 text-white opacity-0 group-hover:opacity-100 transition duration-500">
                    <span className="text-sm tracking-wide">View Project →</span>
                  </div>
                </div>
                <h3 className="mt-4 text-lg">{p.title}</h3>
                <p className="text-sm text-neutral-500">{p.location}</p>
              </a>
            </FadeUp>
          ))}
        </div>
      </section>

    </main>
  );
}

"use client";

import { useEffect, useRef } from "react";
import gsap from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";

gsap.registerPlugin(ScrollTrigger);

export default function ParallaxImage() {
  const ref = useRef<HTMLDivElement | null>(null);

  useEffect(() => {
    const isMobile = window.matchMedia("(max-width: 768px)").matches;

    // 🚫 Disable on mobile
    if (isMobile) return;

    const ctx = gsap.context(() => {
      const img = ref.current?.querySelector(".parallax-img");

      if (!img) return;

      gsap.to(img, {
        y: -80, // slightly reduced for smoother feel
        ease: "none",
        scrollTrigger: {
          trigger: ref.current,
          start: "top bottom",
          end: "bottom top",
          scrub: 0.5, // 🔥 smoother + less heavy than true
        },
      });
    }, ref);

    return () => ctx.revert();
  }, []);

  return (
    <section
      ref={ref}
      className="h-[120vh] flex items-center justify-center overflow-hidden"
    >
      <div className="overflow-hidden">
        <img
          src="/images/hero.jpg"
          className="parallax-img w-[600px] object-cover"
        />
      </div>
    </section>
  );
}

"use client";

import { useEffect } from "react";
import { usePathname } from "next/navigation";
import { initSmoothScroll } from "@/lib/smoothScroll";

export default function SmoothScrollProvider({
  children,
}: {
  children: React.ReactNode;
}) {
  const pathname = usePathname();

  useEffect(() => {
    if (pathname.startsWith("/studio") || pathname.startsWith("/sanity")) {
      // 🚫 Studio Fix: Force dark background and hide browser scrollbar for Studio routes
      document.body.style.background = "#0d0e12"; // matches Sanity dark theme
      document.documentElement.style.overflow = "hidden";
      document.body.style.overflow = "hidden";
      // @ts-ignore - resolve scrollbar gutter issues
      document.documentElement.style.scrollbarGutter = "auto";
      document.body.style.paddingRight = "0px";
      return;
    }

    // Restore for other pages
    document.body.style.background = "";
    document.documentElement.style.overflow = "";
    document.body.style.overflow = "";
    // @ts-ignore
    document.documentElement.style.scrollbarGutter = "";
    document.body.style.paddingRight = "";

    // Use matchMedia instead of raw width (more reliable)
    const isMobile = window.matchMedia("(max-width: 768px)").matches;

    const prefersReducedMotion = window.matchMedia(
      "(prefers-reduced-motion: reduce)"
    ).matches;

    if (isMobile || prefersReducedMotion) return;

    const cleanup = initSmoothScroll();

    return () => {
      cleanup();
    };
  }, [pathname]);

  return <>{children}</>;
}
